    // Simulated annealing parameters with adaptive cooling
    static double temperature = 1000.0;
    static double cooling_rate = 0.95;
    static double min_temperature = 1e-5;
    static int iteration = 0;
    static int accept_count = 0;
    static double target_accept_rate = 0.44;

    // Memory-based diversification
