        if (compare_map<DO_AREA>(worst_arrival, best_arrival, area_local, best_area_flow, cut->size(), best_size)) {
            accept = true;
        } else {
            // Enhanced adaptive acceptance probability
            double delta_arrival = worst_arrival - best_arrival;
            double delta_area = area_local - best_area_flow;
