        }
        cooling_rate = std::min(std::max(cooling_rate, 0.9), 0.999);
    }

    // Restart if stagnating
    if (stagnation_count > 100) {
        temperature = 1000.0;
        cooling_rate = 0.95;
        stagnation_count = 0;
    }

